inline uint32_t get_value(char32_t cp) {
  if (cp > 0x10FFFF) {
    return 0;
  }
  auto i = cp / _block_size;
  auto bl = _blocks[i];
  if (bl) {
    auto off = cp % _block_size;
    return bl[off];
  }
  return _block_values[i];
}
